// --- helpers ---
export const getProduct = (id: string) => products.find((p) => p.id === id);
export const getProductBySku = (sku: string) => products.find((p) => p.sku === sku);
export const productsByCategory = (category: string) => products.filter((p) => p.category.toLowerCase() === category.toLowerCase());
export const totalStock = (p: Product) => Object.values(p.stockByWarehouse).reduce((a, b) => a + b, 0);
export const lowStockProducts = () => products.filter((p) => totalStock(p) < p.reorderPoint * 2);
export const categories = Array.from(new Set(products.map((p) => p.category)));
